mapper.delete:
delete from activity_plan
where id in

    #{id}

mapper.select:
select id, plan_name, min_age, max_age,
       activity_category, season, duration,
       scene, status,cover_url,
       create_time, update_time, create_user, update_user
from activity_plan


        and plan_name like concat('%',#{dto.planName},'%')


        and activity_category = #{dto.activityCategory}


        and status=#{dto.status}


        and (season & #{dto.season})!=0


        and scene=#{dto.scene}


        and min_age >= #{dto.minAge}


        and max_age <= #{dto.maxAge}


        and duration >= #{dto.minDuration}


        and duration <= #{dto.maxDuration}


order by create_time asc

select count(*)
from activity_plan
where create_time >= #{startTime}
  and create_time < #{endTime}
